/**
 * Function: Test node closure functionality
 *
 * @param nodeName Name for the observer node
 * @return bool Whether node closure worked correctly (relationships cleaned up)
 */
bool test_node_closure(const std::string& nodeName) {
    // 1. Create a TestObserverClosure instance (observer) and a reaction::ObserverNode instance (target)
    auto observer = std::make_shared<TestObserverClosure>(nodeName);
    auto target = std::make_shared<reaction::ObserverNode>();

    // 2. Get the global ObserverGraph instance using ObserverGraph::getInstance()
    auto& observerGraph = reaction::ObserverGraph::getInstance();

    // 3. Add an observer relationship from target to observer using ObserverGraph::addObserver()
    observerGraph.addObserver(target, observer);

    // 4. Notify the target (using valueChanged()) and verify the observer was notified
    bool firstTestPassed = false;
    {
        // Set up verification expectations
        bool expectedChanged = true;
        int expectedCallCount = 1;

        // Notify target - this should trigger the observer
        target->valueChanged(true);

        // Verify observer was notified
        if (observer->wasChanged() == expectedChanged && 
            observer->getCallCount() == expectedCallCount) {
            firstTestPassed = true;
        }
    }

    // 5. Reset the observer's state and close the observer node
    observer->m_changed = false;
    observer->m_callCount = 0;
    observer->close();

    // 6. Notify the target again and verify the observer was not notified
    bool secondTestPassed = false;
    {
        // Set up verification expectations
        bool expectedChanged = false;
        int expectedCallCount = 0; // should remain at reset value

        // Notify target again
        target->valueChanged(true);

        // Verify observer was NOT notified
        if (observer->wasChanged() == expectedChanged && 
            observer->getCallCount() == expectedCallCount) {
            secondTestPassed = true;
        }
    }

    // 7. Return true if all tests pass, false otherwise
    return firstTestPassed && secondTestPassed;
}

