 */
std::string test_named_reactions(int valueA, int valueB) {
    using namespace reaction;

    // 1. Create named reactive variable varA with initial value valueA and name "varA"
    auto varA = var(valueA).setName("varA");

    // 2. Create named reactive variable varB with initial value valueB and name "varB"
    auto varB = var(valueB).setName("varB");

    // 3. Create calculation calcAB that depends on both variables (sum) and set name to "calcAB"
    auto calcAB = calc([&]() { 
        return varA() + varB(); 
    }).setName("calcAB");

    // 4. Create action actionAB that modifies both variables (increment by 1) and set name to "actionAB"
    auto actionAB = action([&]() {
        varA.value(varA.get() + 1);
        varB.value(varB.get() + 1);
    }).setName("actionAB");

    // 5. Use getName() method to retrieve the names of all created nodes
    std::string varAName = varA.getName();
    std::string varBName = varB.getName();
    std::string calcABName = calcAB.getName();
    std::string actionABName = actionAB.getName();

    // 6. Combine the names into a single string in the specified order
    std::string combinedNames = varAName + varBName + calcABName + actionABName;

    // 7. Return the combined string
    return combinedNames;
}

}  // namespace test_reaction
