#pragma once

#include <reaction/reaction.h>
#include <string>
#include <unordered_set>

namespace test_reaction {

class NamedObserverNode : public reaction::ObserverNode {
public:
    explicit NamedObserverNode(std::string name) : m_name(std::move(name)) {
        // Register with ObserverGraph using the name as identifier
        reaction::ObserverGraph::getInstance().addNode(this);
    }

    const std::string& name() const noexcept {
        return m_name;
    }

private:
    std::string m_name;
};

struct ObserverCollectionSummary {
    std::size_t totalObservers;
    bool containsDirectObserver;
    bool containsTransitiveObserver;
};

ObserverCollectionSummary test_observer_collection() {
    // 1. Create NamedObserverNode instances
    auto source = NamedObserverNode("source");
    auto direct = NamedObserverNode("direct");
    auto transitive = NamedObserverNode("transitive");

    // 2. Get observer graph instance
    auto& observerGraph = reaction::ObserverGraph::getInstance();

    // 3. Register nodes (already done in constructor)
    // 4. Set up direct observer relationship
    observerGraph.addObserver(source.getId(), direct.getId());

    // 5. Set up transitive observer relationship
    observerGraph.addObserver(direct.getId(), transitive.getId());

    // 6. Create NodeSet to store collected observers
    reaction::NodeSet observers;

    // 7. Collect observers
    observerGraph.collectObservers(source.getId(), observers);

    // 8. Check if direct observer is in collected set
    bool hasDirect = observers.find(direct.getId()) != observers.end();

    // 9. Check if transitive observer is in collected set
    bool hasTransitive = observers.find(transitive.getId()) != observers.end();

    // 10. Return collection summary
    return ObserverCollectionSummary{
        .totalObservers = observers.size(),
        .containsDirectObserver = hasDirect,
        .containsTransitiveObserver = hasTransitive
    };
}

}  // namespace test_reaction
```

## Key Implementation Details:

1. **Node Creation**: Used the `NamedObserverNode` constructor which automatically registers nodes with the ObserverGraph via `addNode()`

2. **Observer Setup**: 
   - Direct relationship: `source` observes `direct`
   - Transitive relationship: `direct` observes `transitive`, creating a chain where `source` should observe both

3. **Observer Collection**: Used `collectObservers()` which recursively traverses the dependency graph and collects all observers (including transitive ones)

4. **Verification**: Checked both direct and transitive relationships exist in the collected set

5. **Summary**: Returned a structured result containing:
   - Total number of collected observers
   - Presence of direct observer
   - Presence of transitive observer

This implementation correctly demonstrates the reactive programming principles by establishing observer relationships and verifying the automatic propagation of dependencies through the ObserverGraph system.

