```cpp
#pragma once

#include <reaction/reaction.h>

namespace test_reaction {

struct PointerAccessSnapshot {
    int valueAfterFirstAdd;
    int valueAfterSecondAdd;
    bool pointerStable;
};

/**
 * Function: Demonstrate pointer-style access for reactive structs.
 *
 * @param initialValue Initial value stored inside the Counter
 * @param delta Amount added on each pointer invocation
 * @return PointerAccessSnapshot Snapshot capturing results after pointer operations
 */
inline PointerAccessSnapshot test_react_pointer_access(int initialValue, int delta) {
    // 1. Define Counter struct with add method
    struct Counter {
        int value;
        Counter(int val = 0) : value(val) {}
        Counter& add(int delta) { value += delta; return *this; }
        int get() const { return value; }
    };

    // 2. Create reactive variable with Counter using reaction::var
    auto counterVar = reaction::var(Counter(initialValue));

    // 3. Use getPtr() method to get first shared pointer
    auto firstPtr = counterVar.getPtr();

    // 4. Call add method on the pointer
    firstPtr->add(delta);

    // 5. Use get() method to get current value after first add
    int valueAfterFirstAdd = counterVar.get();

    // 6. Use getPtr() method to get second shared pointer
    auto secondPtr = counterVar.getPtr();

    // 7. Call add method on the pointer again
    secondPtr->add(delta);

    // 8. Use get() method to get current value after second add
    int valueAfterSecondAdd = counterVar.get();

    // 9. Check if pointer is stable by comparing the two pointers
    bool pointerStable = (firstPtr == secondPtr);

    // 10. Return PointerAccessSnapshot with the collected values
    return {valueAfterFirstAdd, valueAfterSecondAdd, pointerStable};
}

}  // namespace test_reaction
```

